const raw = $input.first().json.output || $input.first().json.text || '';

// Extract JSON array from response (handle markdown code fences)
let jsonStr = raw;
const fenceMatch = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
if (fenceMatch) {
  jsonStr = fenceMatch[1].trim();
}

// Try to find array brackets if not already clean
const arrayMatch = jsonStr.match(/(\[[\s\S]*\])/);
if (arrayMatch) {
  jsonStr = arrayMatch[1];
}

let strategies;
try {
  strategies = JSON.parse(jsonStr);
} catch (e) {
  return [{
    json: {
      error: 'Failed to parse Ollama output as JSON',
      raw_output: raw.substring(0, 500),
      parse_error: e.message
    }
  }];
}

if (!Array.isArray(strategies)) {
  strategies = [strategies];
}

const enriched = strategies.map(s => ({
  json: {
    strategy_name: s.strategy_name || 'unnamed',
    one_sentence: s.one_sentence || '',
    python_code: s.python_code || '',
    params: s.params || {},
    symbol: 'ES',
    timeframe: '15min',
    start_date: '2024-01-01',
    end_date: '2024-12-31',
    source: 'ollama'
  }
}));

return enriched;

const items = $input.all();
let scoutedIdeas = [];

// Parse scouted ideas from API response
for (const item of items) {
  const d = item.json;
  if (Array.isArray(d)) {
    scoutedIdeas = d;
  } else if (d.ideas && Array.isArray(d.ideas)) {
    scoutedIdeas = d.ideas;
  } else if (d.entries && Array.isArray(d.entries)) {
    scoutedIdeas = d.entries;
  } else if (d.data && Array.isArray(d.data)) {
    scoutedIdeas = d.data;
  }
}

// Get the market regime data from upstream
let regimeData = {};
try {
  regimeData = $('Detect Market Regime').first().json || {};
} catch(e) { regimeData = {}; }

let scoutContext = '';
if (scoutedIdeas.length > 0) {
  const ideaSummaries = scoutedIdeas.slice(0, 10).map((idea, i) => {
    const title = idea.title || idea.name || 'Untitled';
    const summary = idea.summary || idea.description || '';
    const source = idea.source || 'unknown';
    return `${i + 1}. [${source}] ${title}: ${summary.substring(0, 150)}`;
  }).join('\n');
  scoutContext = `\n\nRecent research discoveries to consider when generating strategies:\n${ideaSummaries}`;
}

return [{ json: { ...regimeData, scoutContext, scoutedIdeaCount: scoutedIdeas.length } }];

